# Plan: Extract Service Layer from Route Handlers

## Context

`src/routes/products.ts` and `src/routes/orders.ts` currently mix HTTP concerns (parsing params, sending responses) with business logic (filtering, calculations, validation, state mutations). This makes the logic hard to unit-test and maintain. The refactor extracts all business logic into dedicated service files while keeping route handlers as thin HTTP adapters. No tests need to change — the public API (HTTP endpoints) stays identical.

---

## Files to Create

- `src/services/product-service.ts`
- `src/services/order-service.ts`

## Files to Modify

- `src/types.ts` — add shared result/response types
- `src/routes/products.ts` — replace business logic with service calls
- `src/routes/orders.ts` — replace business logic with service calls

---

## Step-by-Step Implementation

### Step 1 — Add types to `src/types.ts`

Append the following exports. Existing types (`Product`, `Order`, `OrderItem`, `CreateOrderInput`) are **unchanged**.

```typescript
// Shared service result type (discriminated union)
export type ServiceResult<T> =
  | { ok: true; data: T }
  | { ok: false; status: 400 | 404; message: string };

// Product service return shapes
export interface ProductDetail extends Product {
  isLowStock: boolean;
  inventoryValue: number;
}

export interface ProductListResult {
  products: Product[];
  summary: {
    count: number;
    totalInventoryValue: number;
    averagePrice: number;
  };
}

// Order service return shapes
export interface EnrichedOrderItem extends OrderItem {
  productName: string;
}

export interface EnrichedOrder extends Omit<Order, "items"> {
  items: EnrichedOrderItem[];
}

export interface OrderListResult {
  orders: Order[];
  summary: {
    count: number;
    totalRevenue: number;
  };
}
```

---

### Step 2 — Create `src/services/product-service.ts`

```typescript
import { products } from "../data.js";
import type {
  Product,
  ProductDetail,
  ProductListResult,
  ServiceResult,
} from "../types.js";

// Business rule helpers
function toProductDetail(product: Product): ProductDetail {
  return {
    ...product,
    isLowStock: product.stock < 10,
    inventoryValue: Math.round(product.price * product.stock * 100) / 100,
  };
}

// GET /products — filter + summarise
export function listProducts(filters: {
  category?: string;
  minPrice?: number;
  maxPrice?: number;
}): ProductListResult {
  let filtered = [...products];

  if (filters.category !== undefined) {
    filtered = filtered.filter((p) => p.category === filters.category);
  }
  if (filters.minPrice !== undefined) {
    filtered = filtered.filter((p) => p.price >= filters.minPrice!);
  }
  if (filters.maxPrice !== undefined) {
    filtered = filtered.filter((p) => p.price <= filters.maxPrice!);
  }

  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice =
    filtered.length > 0
      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
      : 0;

  return {
    products: filtered,
    summary: {
      count: filtered.length,
      totalInventoryValue: Math.round(totalValue * 100) / 100,
      averagePrice: Math.round(avgPrice * 100) / 100,
    },
  };
}

// GET /products/:id
export function getProductById(id: number): ProductDetail | null {
  const product = products.find((p) => p.id === id);
  if (!product) return null;
  return toProductDetail(product);
}

// PATCH /products/:id/stock
// Precondition: adjustment is already validated as a number by the route handler
export function updateProductStock(
  id: number,
  adjustment: number
): ServiceResult<ProductDetail> {
  const product = products.find((p) => p.id === id);
  if (!product) {
    return { ok: false, status: 404, message: "Product not found" };
  }

  const newStock = product.stock + adjustment;
  if (newStock < 0) {
    return { ok: false, status: 400, message: "Insufficient stock" };
  }

  product.stock = newStock;
  return { ok: true, data: toProductDetail(product) };
}
```

---

### Step 3 — Create `src/services/order-service.ts`

```typescript
import { orders, products, getNextOrderId } from "../data.js";
import type {
  CreateOrderInput,
  EnrichedOrder,
  OrderItem,
  OrderListResult,
  ServiceResult,
  Order,
} from "../types.js";

const VALID_STATUSES = ["pending", "confirmed", "shipped", "delivered"] as const;
const STATUS_TRANSITIONS: Record<string, string[]> = {
  pending: ["confirmed"],
  confirmed: ["shipped"],
  shipped: ["delivered"],
  delivered: [],
};

// GET /orders — filter + summarise
export function listOrders(filters: {
  userId?: number;
  status?: string;
}): OrderListResult {
  let filtered = [...orders];

  if (filters.userId !== undefined) {
    filtered = filtered.filter((o) => o.userId === filters.userId);
  }
  if (filters.status !== undefined) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}

// GET /orders/:id — enrich items with product names
export function getOrderById(id: number): EnrichedOrder | null {
  const order = orders.find((o) => o.id === id);
  if (!order) return null;

  const enrichedItems = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return { ...item, productName: product?.name ?? "Unknown" };
  });

  return { ...order, items: enrichedItems };
}

// POST /orders — validate items, deduct stock, persist
// Precondition: input.userId exists and input.items is a non-undefined array
export function createOrder(
  input: CreateOrderInput
): ServiceResult<Order> {
  if (input.items.length === 0) {
    return { ok: false, status: 400, message: "Order must have at least one item" };
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      return { ok: false, status: 400, message: `Product ${item.productId} not found` };
    }
    if (item.quantity <= 0) {
      return { ok: false, status: 400, message: "Quantity must be positive" };
    }
    if (product.stock < item.quantity) {
      return { ok: false, status: 400, message: `Insufficient stock for ${product.name}` };
    }

    product.stock -= item.quantity;
    orderItems.push({ productId: product.id, quantity: item.quantity, price: product.price });
    total += product.price * item.quantity;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);
  return { ok: true, data: order };
}

// PATCH /orders/:id/status — validate transition, update
// Precondition: status is already validated as a string by the route handler
export function updateOrderStatus(
  id: number,
  status: string
): ServiceResult<Order> {
  const order = orders.find((o) => o.id === id);
  if (!order) {
    return { ok: false, status: 404, message: "Order not found" };
  }

  if (!(VALID_STATUSES as readonly string[]).includes(status)) {
    return {
      ok: false,
      status: 400,
      message: `Invalid status. Must be one of: ${VALID_STATUSES.join(", ")}`,
    };
  }

  if (!STATUS_TRANSITIONS[order.status]?.includes(status)) {
    return {
      ok: false,
      status: 400,
      message: `Cannot transition from ${order.status} to ${status}`,
    };
  }

  order.status = status as Order["status"];
  return { ok: true, data: order };
}
```

---

### Step 4 — Rewrite `src/routes/products.ts`

Route handlers now only: parse HTTP input → call service → send response.

```typescript
import { Router } from "express";
import {
  listProducts,
  getProductById,
  updateProductStock,
} from "../services/product-service.js";

const router = Router();

router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;

  const filters = {
    category: typeof category === "string" ? category : undefined,
    minPrice:
      typeof minPrice === "string" && !isNaN(parseFloat(minPrice))
        ? parseFloat(minPrice)
        : undefined,
    maxPrice:
      typeof maxPrice === "string" && !isNaN(parseFloat(maxPrice))
        ? parseFloat(maxPrice)
        : undefined,
  };

  res.json(listProducts(filters));
});

router.get("/products/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const product = getProductById(id);

  if (!product) {
    res.status(404).json({ error: "Product not found" });
    return;
  }

  res.json(product);
});

router.patch("/products/:id/stock", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const { adjustment } = req.body as { adjustment: unknown };

  if (typeof adjustment !== "number") {
    res.status(400).json({ error: "adjustment must be a number" });
    return;
  }

  const result = updateProductStock(id, adjustment);
  if (!result.ok) {
    res.status(result.status).json({ error: result.message });
    return;
  }

  res.json(result.data);
});

export { router as productRouter };
```

---

### Step 5 — Rewrite `src/routes/orders.ts`

```typescript
import { Router } from "express";
import {
  listOrders,
  getOrderById,
  createOrder,
  updateOrderStatus,
} from "../services/order-service.js";
import type { CreateOrderInput } from "../types.js";

const router = Router();

router.get("/orders", (req, res) => {
  const { userId, status } = req.query;

  const filters = {
    userId:
      typeof userId === "string" && !isNaN(parseInt(userId, 10))
        ? parseInt(userId, 10)
        : undefined,
    status: typeof status === "string" ? status : undefined,
  };

  res.json(listOrders(filters));
});

router.get("/orders/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const order = getOrderById(id);

  if (!order) {
    res.status(404).json({ error: "Order not found" });
    return;
  }

  res.json(order);
});

router.post("/orders", (req, res) => {
  const input = req.body as CreateOrderInput;

  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    res.status(400).json({ error: "userId and items are required" });
    return;
  }

  const result = createOrder(input);
  if (!result.ok) {
    res.status(result.status).json({ error: result.message });
    return;
  }

  res.status(201).json(result.data);
});

router.patch("/orders/:id/status", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const { status } = req.body as { status: unknown };

  if (typeof status !== "string") {
    res.status(400).json({ error: "status must be a string" });
    return;
  }

  const result = updateOrderStatus(id, status);
  if (!result.ok) {
    res.status(result.status).json({ error: result.message });
    return;
  }

  res.json(result.data);
});

export { router as orderRouter };
```

---

## Separation of Concerns Summary

| Concern | Route Handler | Service |
|---|---|---|
| Parse query/body params | ✅ | ❌ |
| Validate required HTTP fields (`userId`, `items`) | ✅ | ❌ |
| Validate body field types (`adjustment` is number, `status` is string) | ✅ | ❌ |
| Send HTTP status codes and JSON | ✅ | ❌ |
| Filter / search logic | ❌ | ✅ |
| Calculate derived fields (`isLowStock`, `inventoryValue`, `totalRevenue`) | ❌ | ✅ |
| Business validation (items > 0, stock sufficient, valid transition) | ❌ | ✅ |
| Mutate in-memory data | ❌ | ✅ |

---

## Verification

Run the existing test suite — no test changes required:

```bash
npm test
```

All 10 tests across `tests/products.test.ts` (5) and `tests/orders.test.ts` (5) must pass. The HTTP API surface is unchanged, so the supertest integration tests verify correctness end-to-end without modification.

